            mnist,
            bufs,
            indices,
            batch,
            group_size,
        );

        // Wait for the previous command buffer to finish
        // before encoding (SGD wrote to params there).
        if (prev_cmd) |pc| {
            pc.msgSend(void, "waitUntilCompleted", .{});
        }

        // Phase 2: encode all batches in a single
        // command buffer + compute encoder.
