            device,
            net,
            bufs,
            batch,
            group_size,
        );

        batch += group_size;
    }

    // Wait for the final command buffer.
    if (prev_cmd) |pc| {
        pc.msgSend(void, "waitUntilCompleted", .{});
    }

    return sumSlice(bufs.loss.asSlice()) /
        @as(f32, max_batch);
