// ============================================================================
// SGD parameter update
// ============================================================================

/// params[i] -= lr * grads[i]
kernel void sgd_update(
    device float*       params [[buffer(0)]],
    device const float* grads  [[buffer(1)]],
    constant float& lr         [[buffer(2)]],
    uint                gid    [[thread_position_in_grid]])
{
    params[gid] -= lr * grads[gid];
}

// ============================================================================
// Fused backward + SGD kernels
// ============================================================================

/// Fused weight gradient + SGD: compute Xᵀ·dY and update params
/// in one dispatch.  Eliminates the separate sgd_update dispatch
/// and its gradient buffer read.
///   A = X [M × K], B = dY [M × N], output = [K × N].
///   params[offset + row*N + col] -= lr * (Aᵀ · B)[row, col]
kernel void weight_grad_sgd(
    device const float* A      [[buffer(0)]],  // X [M × K]
    device const float* B      [[buffer(1)]],  // dY [M × N]
    device float*       params [[buffer(2)]],  // param buffer
    constant uint& M           [[buffer(3)]],
    constant uint& K           [[buffer(4)]],
    constant uint& N           [[buffer(5)]],
    constant float& lr         [[buffer(6)]],
    uint2 gid                  [[thread_position_in_grid]],
    uint2 lid                  [[thread_position_in_threadgroup]])
{
    threadgroup float tileA[TS * TS];
    threadgroup float tileB[TS * TS];

    const uint out_row = gid.y;  // k
    const uint out_col = gid.x;  // n

    float sum = 0.0f;

    // Tile over M (the summation/contraction dimension).
    const uint num_tiles = (M + TS - 1) / TS;
    for (uint t = 0; t < num_tiles; t++) {
        // Load Aᵀ tile: element [out_row, t*TS+lid.x]
        // = A[t*TS+lid.x, out_row] in original layout.
        const uint m_idx = t * TS + lid.x;
        if (out_row < K && m_idx < M) {
            tileA[lid.y * TS + lid.x] =
                A[m_idx * K + out_row];
        } else {
            tileA[lid.y * TS + lid.x] = 0.0f;
        }

        // Load B tile: element [t*TS+lid.y, out_col].
        const uint m_idy = t * TS + lid.y;
        if (m_idy < M && out_col < N) {
            tileB[lid.y * TS + lid.x] =
                B[m_idy * N + out_col];
        } else {
            tileB[lid.y * TS + lid.x] = 0.0f;
        }

        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint i = 0; i < TS; i++) {
            sum += tileA[lid.y * TS + i]
                 * tileB[i * TS + lid.x];
        }

        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    // Fused SGD: apply gradient directly to params.
    if (out_row < K && out_col < N) {
        params[out_row * N + out_col] -= lr * sum;
    }
}

/// Fused bias gradient + SGD: column-wise sum of gradients,
/// applied directly to params.  Eliminates the separate
/// sgd_update dispatch for bias parameters.
///   params[gid] -= lr * sum_m(input[m * N + gid])
kernel void bias_grad_sgd(
    device const float* input  [[buffer(0)]],  // [M × N]
    device float*       params [[buffer(1)]],  // param buffer
    constant uint& M           [[buffer(2)]],
    constant uint& N           [[buffer(3)]],
    constant float& lr         [[buffer(4)]],
    uint                gid    [[thread_position_in_grid]])
{
    if (gid >= N) return;

    float sum = 0.0;
    for (uint m = 0; m < M; m++) {
        sum += input[m * N + gid];
    }
    params[gid] -= lr * sum;
}

