/// Encode bias gradient: column-wise sum of
/// grad_pre_act [batch × out] → grads at
/// bias_offset.  Each thread sums one column.
fn encodeBiasGrad(
    comptime out_size: u32,
    comptime bias_offset: u32,
    device: *const Device,
    encoder: objc.Object,
    grad_pre_act: Buffer,
    grads: Buffer,
    batch_size: u32,
