/// Dispatches the sgd_update kernel over the full
/// parameter buffer.  Requires a prior backward()
/// call so that grads are populated.
pub fn update(
    self: *const Self,
    device: *const Device,
    encoder: objc.Object,
    learning_rate: f32,
) void {
    std.debug.assert(learning_rate > 0.0);
    std.debug.assert(
        self.params.len == Layout.param_count,
    );

