        &learning_rate,
        2,
    );

    device.dispatch1D(
        encoder,
        device.sgd_update,
        Layout.param_count,
    );
    // No barrier needed: Metal serialises dispatches
    // within a single compute encoder. The next
    // forward pass reads params via the same encoder.
}

// ====================================================
// Fused backward + SGD
// ====================================================

/// Encode backward pass with fused SGD: weight and
/// bias gradients are applied directly to params
/// inside the gradient kernels.  Eliminates the
/// separate sgd_update dispatch (saves 1 dispatch
/// + 109k gradient buffer reads per batch).
pub fn backwardSGD(
    self: *const Self,
    device: *const Device,
    encoder: objc.Object,
    input: Buffer,
    loss_grad: Buffer,
    batch_size: u32,
    learning_rate: f32,
) void {
    std.debug.assert(batch_size > 0);
    std.debug.assert(batch_size <= max_batch_size);
    std.debug.assert(learning_rate > 0.0);
    std.debug.assert(
        loss_grad.len >=
            batch_size * Layout.output_size,
    );

    comptime var active: u1 = 0;

    inline for (0..Layout.num_layers) |fwd_i| {
        const i = Layout.num_layers - 1 - fwd_i;
        const is_last =
            (i == Layout.num_layers - 1);
        const act = Layout.layers[i].act;

        const layer_input: Buffer =
            if (i == 0)
                input
            else
                self.post_activations[i - 1];

        if (act != .none) {
            active = backwardLayerActSGD(
                i,
                is_last,
                active,
                act,
                self,
                device,
                encoder,
                layer_input,
                loss_grad,
                batch_size,
                learning_rate,
            );
        } else {
            active = backwardLayerNoneSGD(
                i,
                is_last,
                active,
                self,
                device,
                encoder,
                layer_input,
                loss_grad,
                batch_size,
                learning_rate,
            );
        }
    }
}

/// Backward layer with activation + fused SGD.
/// Returns the updated active scratch index.
fn backwardLayerActSGD(
    comptime i: usize,
    comptime is_last: bool,
    comptime active_in: u1,
    comptime act: layout.Activation,
    self: *const Self,
    device: *const Device,
    encoder: objc.Object,
    layer_input: Buffer,
    loss_grad: Buffer,
    batch_size: u32,
    learning_rate: f32,
) u1 {
    std.debug.assert(batch_size > 0);
    std.debug.assert(learning_rate > 0.0);

    const target: u1 =
        comptime if (is_last) 0 else 1 - active_in;

    const grad_output: Buffer =
        if (is_last)
            loss_grad
        else
            self.backward_scratch[active_in];

    encodeActivationBackward(
        act,
        Layout.layers[i].out,
        device,
        encoder,
        self.pre_activations[i],
        self.post_activations[i],
        grad_output,
        self.backward_scratch[target],
        batch_size,
    );

    encodeBiasGradSGD(
        Layout.layers[i].out,
        Layout.bias_offsets[i],
        device,
        encoder,
        self.backward_scratch[target],
        self.params,
        batch_size,
        learning_rate,
    );

    encodeWeightGradSGD(
        Layout.layers[i].in,
        Layout.layers[i].out,
        Layout.weight_offsets[i],
        device,
        encoder,
        layer_input,
        self.backward_scratch[target],
        self.params,
        batch_size,
        learning_rate,
    );

    if (i > 0) {
        const ig_target: u1 =
            comptime if (is_last) 1 else active_in;

        encodeInputGrad(
            Layout.layers[i].in,
            Layout.layers[i].out,
            Layout.weight_offsets[i],
            device,
            encoder,
            self.backward_scratch[target],
            self.params,
            self.backward_scratch[ig_target],
            batch_size,
        );
        return ig_target;
    }
    return active_in;
}

/// Backward layer without activation + fused SGD.
/// Returns the updated active scratch index.
fn backwardLayerNoneSGD(
    comptime i: usize,
    comptime is_last: bool,
    comptime active_in: u1,
    self: *const Self,
    device: *const Device,
    encoder: objc.Object,
    layer_input: Buffer,
    loss_grad: Buffer,
    batch_size: u32,
    learning_rate: f32,
) u1 {
    std.debug.assert(batch_size > 0);
    std.debug.assert(learning_rate > 0.0);

    const grad_pre_act: Buffer =
        if (is_last)
            loss_grad
        else
            self.backward_scratch[active_in];

    encodeBiasGradSGD(
        Layout.layers[i].out,
        Layout.bias_offsets[i],
        device,
        encoder,
        grad_pre_act,
        self.params,
        batch_size,
        learning_rate,
    );

    encodeWeightGradSGD(
        Layout.layers[i].in,
        Layout.layers[i].out,
        Layout.weight_offsets[i],
        device,
        encoder,
        layer_input,
        grad_pre_act,
        self.params,
        batch_size,
        learning_rate,
    );

    if (i > 0) {
        const ig_target: u1 =
            comptime if (is_last)
                0
            else
                1 - active_in;

        encodeInputGrad(
            Layout.layers[i].in,
            Layout.layers[i].out,
            Layout.weight_offsets[i],
            device,
            encoder,
            grad_pre_act,
            self.params,
            self.backward_scratch[ig_target],
            batch_size,
        );
        return ig_target;
    }
    return active_in;
}

