// ============================================================================
// Fused activation backward + bias gradient
// ============================================================================

/// Fused ReLU backward + bias gradient: apply ReLU mask to
/// upstream gradient AND compute column-wise sum in one pass.
/// Saves one dispatch per ReLU layer in the backward pass.
///
/// Each thread handles one column (output neuron), iterating
/// over all rows (batch samples).  Writes:
///   grad_in[row * N + col] = grad_out[row*N+col] * (pre[row*N+col] > 0)
///   bias_grad[col] = sum_row grad_in[row * N + col]
kernel void relu_backward_bias_grad(
    device const float* pre_act   [[buffer(0)]],  // [M × N]
    device const float* grad_out  [[buffer(1)]],  // [M × N]
    device float*       grad_in   [[buffer(2)]],  // [M × N]
    device float*       bias_grad [[buffer(3)]],  // [N]
    constant uint& M              [[buffer(4)]],
    constant uint& N              [[buffer(5)]],
    uint                gid       [[thread_position_in_grid]])
{
    if (gid >= N) return;

    float sum = 0.0f;
    for (uint m = 0; m < M; m++) {
        const uint idx = m * N + gid;
        // ReLU backward: zero out gradient where pre-activation <= 0.
        float g = pre_act[idx] > 0.0f ? grad_out[idx] : 0.0f;
        grad_in[idx] = g;
        sum += g;
    }
    bias_grad[gid] = sum;
}

