fn evaluate(
    device: *const Device,
    net: *const MnistNet,
    bufs: *const Buffers,
    images: []const f32,
    labels_onehot: []const f32,
    labels_raw: []const u8,
    indices: []const u32,
) EvalResult {
    const count: u32 = @intCast(indices.len);
    std.debug.assert(count > 0);
    std.debug.assert(images.len > 0);
    std.debug.assert(labels_raw.len > 0);

    var correct: u32 = 0;
    var loss_sum: f64 = 0.0;
    var offset: u32 = 0;

    // Double-buffer evaluation: fill batch N+1 on CPU
    // while GPU processes batch N.  Uses buffer slots
    // 0 and 1 alternately.
    var buf_slot: u32 = 0;
    var prev_cmd: ?Object = null;
    var prev_count: u32 = 0;
    var prev_idx: []const u32 = &.{};

    while (offset < count) {
        const remaining = count - offset;
        const current: u32 = @min(max_batch, remaining);
        const idx = indices[offset..][0..current];

        // CPU fill for current batch (overlapped with
        // GPU processing previous batch).
        Mnist.fillImageBatch(
            images,
            idx,
            bufs.inputs[buf_slot].asSlice(),
        );
        Mnist.fillLabelBatch(
            labels_onehot,
            idx,
            bufs.targets[buf_slot].asSlice(),
        );

        // Wait for previous GPU work and collect results.
        if (prev_cmd) |pc| {
            pc.msgSend(void, "waitUntilCompleted", .{});

            for (bufs.loss.asSlice()[0..prev_count]) |v| {
                loss_sum += @as(f64, v);
            }
            correct += countCorrect(
                net.getOutput().asSlice(),
                labels_raw,
                prev_idx,
                prev_count,
            );
        }

        // Encode and submit GPU work for current batch.
        const cmd = device.beginCommandBuffer();
        const enc = device.beginCompute(cmd);
        net.forward(
            device,
            enc,
            bufs.inputs[buf_slot],
            current,
        );
        encodeLoss(
            device,
            net,
            bufs,
            bufs.targets[buf_slot],
            current,
            enc,
        );
        enc.msgSend(void, "endEncoding", .{});
        device.commit(cmd);

        prev_cmd = cmd;
        prev_count = current;
        prev_idx = idx;
        buf_slot = 1 - buf_slot;
        offset += current;
    }

    // Collect results from the final batch.
    if (prev_cmd) |pc| {
        pc.msgSend(void, "waitUntilCompleted", .{});

        for (bufs.loss.asSlice()[0..prev_count]) |v| {
            loss_sum += @as(f64, v);
        }
        correct += countCorrect(
            net.getOutput().asSlice(),
            labels_raw,
            prev_idx,
            prev_count,
        );
    }

    const n: f64 = @floatFromInt(count);
    const c: f64 = @floatFromInt(correct);

    return .{
        .correct = correct,
        .total = count,
        .mean_loss = @floatCast(loss_sum / n),
        .accuracy_pct = c / n * 100.0,
    };
}

